#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\workspace\Projects\New Page Builder App\packages\page-builder-core\node_modules\acorn\bin\node_modules;C:\workspace\Projects\New Page Builder App\packages\page-builder-core\node_modules\acorn\node_modules;C:\workspace\Projects\New Page Builder App\packages\page-builder-core\node_modules;C:\workspace\Projects\New Page Builder App\packages\node_modules;C:\workspace\Projects\New Page Builder App\node_modules;C:\workspace\Projects\node_modules;C:\workspace\node_modules;C:\node_modules;C:\workspace\Projects\New Page Builder App\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/proc/cygdrive/c/workspace/Projects/New Page Builder App/packages/page-builder-core/node_modules/acorn/bin/node_modules:/proc/cygdrive/c/workspace/Projects/New Page Builder App/packages/page-builder-core/node_modules/acorn/node_modules:/proc/cygdrive/c/workspace/Projects/New Page Builder App/packages/page-builder-core/node_modules:/proc/cygdrive/c/workspace/Projects/New Page Builder App/packages/node_modules:/proc/cygdrive/c/workspace/Projects/New Page Builder App/node_modules:/proc/cygdrive/c/workspace/Projects/node_modules:/proc/cygdrive/c/workspace/node_modules:/proc/cygdrive/c/node_modules:/proc/cygdrive/c/workspace/Projects/New Page Builder App/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../acorn/bin/acorn" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../acorn/bin/acorn" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../acorn/bin/acorn" $args
  } else {
    & "node$exe"  "$basedir/../acorn/bin/acorn" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
